/// Hex-dump up to `limit` bytes with a trailing note if truncated.
fn hex_dump(bytes: &[u8], limit: usize) -> String {
    let truncated = bytes.len() > limit;
    let slice = &bytes[..bytes.len().min(limit)];
    let hex = slice
        .iter()
        .map(|b| format!("{b:02x}"))
        .collect::<Vec<_>>()
        .join(" ");
    if truncated {
        format!("{hex} ... ({} bytes total)", bytes.len())
    } else {
        hex
    }
}
